What does this program print?

```cpp
#include <iostream>
void show(int x)    { std::cout << "int"    << '\n'; }
void show(double x) { std::cout << "double" << '\n'; }
int main() {
    show(1);
    show(2.0);
    show(3.0f);
}
```

What does this program print?

```cpp
#include <iostream>
template <typename T>
T triple(T x) { return x * 3; }
int main() {
    std::cout << triple(4)   << '\n';
    std::cout << triple(1.5) << '\n';
}
```

This program should print the smaller of two integers, but it prints the wrong value. What is the bug?

```cpp
#include <iostream>
template <int N>
int capAt(int x) {
    if (x > N) return x;  // intended: return N when x exceeds cap
    return x;
}
int main() {
    std::cout << capAt<10>(25) << '\n';
}
```
